const items = $input.all();
const normalized = [];

for (const item of items) {
  const email = item.json;

  if (email.from && email.from.emailAddress && 
      email.from.emailAddress.address === 'asing168@jh.edu') {
    continue;
  }

  let body = '';
  if (email.body) {
    if (email.body.contentType === 'html' || email.body.contentType === 'HTML') {
      body = email.body.content.replace(/<[^>]*>/g, ' ').replace(/\s+/g, ' ').trim();
    } else {
      body = email.body.content || '';
    }
  } else if (email.bodyPreview) {
    body = email.bodyPreview;
  }

  const sigPatterns = [/\n--\s*\n[\s\S]*$/, /\nSent from [\s\S]*$/, /\n_{3,}[\s\S]*$/, /\nGet Outlook[\s\S]*$/];
  for (const pattern of sigPatterns) {
    body = body.replace(pattern, '');
  }

  body = body.replace(/\nOn .* wrote:[\s\S]*$/m, '');
  body = body.split('\n').filter(line => !line.startsWith('>')).join('\n');

  if (body.length > 2000) {
    body = body.substring(0, 2000) + '... [truncated]';
  }

  const attachmentNames = [];
  if (email.hasAttachments && email.attachments) {
    for (const att of email.attachments) {
      if (att.name) attachmentNames.push(att.name);
    }
  }
  if (attachmentNames.length > 0) {
    body += '\n[Attachments: ' + attachmentNames.join(', ') + ']';
  }

  let bodyHtml = '';
  if (email.body && (email.body.contentType === 'html' || email.body.contentType === 'HTML')) {
    bodyHtml = email.body.content.substring(0, 500);
  }

  normalized.push({
    json: {
      id: email.id || '',
      source: 'outlook',
      from: {
        name: email.from?.emailAddress?.name || '',
        email: email.from?.emailAddress?.address || ''
      },
      to: (email.toRecipients || []).map(r => ({
        name: r.emailAddress?.name || '',
        email: r.emailAddress?.address || ''
      })),
      subject: email.subject || '(no subject)',
      body: body,
      bodyHtml: bodyHtml,
      date: email.receivedDateTime || '',
      labels: email.categories || [],
      isRead: email.isRead || false,
      hasAttachments: attachmentNames.length > 0,
      attachmentNames: attachmentNames,
      threadId: email.conversationId || '',
      messageCount: 1
    }
  });
}

return normalized.length > 0 ? normalized : [{ json: { emails: [], count: 0 } }];
